(window.webpackJsonp=window.webpackJsonp||[]).push([[540],{835:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">edges</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">succProb</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">start</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">end</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxProbability = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, edges, succProb, start, end</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> g=<span class=\\"hljs-built_in\\">Array</span>(n).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span>[])\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;edges.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> [f,t]=edges[i]\\n        g[f].push([t,succProb[i]])\\n        g[t].push([f,succProb[i]])\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> visited=[]\\n    <span class=\\"hljs-keyword\\">let</span> succSave=[]\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> arr=[[start,<span class=\\"hljs-number\\">1</span>]]\\n    <span class=\\"hljs-keyword\\">while</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n        <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n            <span class=\\"hljs-keyword\\">let</span> [curNode,curSucc]=arr.shift()\\n            <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;g[curNode].length;j++){\\n                <span class=\\"hljs-keyword\\">let</span> [nxtNode,succ]=g[curNode][j]\\n                <span class=\\"hljs-keyword\\">let</span> nxtSucc=succ*curSucc\\n                <span class=\\"hljs-keyword\\">if</span>(nxtNode===end){\\n                    res=<span class=\\"hljs-built_in\\">Math</span>.max(res,nxtSucc)\\n                }\\n                <span class=\\"hljs-keyword\\">if</span>(visited[nxtNode]){\\n                    <span class=\\"hljs-keyword\\">if</span>(succSave[nxtNode]&lt;nxtSucc){\\n                        succSave[nxtNode]=nxtSucc\\n                        arr.push([nxtNode,nxtSucc])\\n                    }\\n                }<span class=\\"hljs-keyword\\">else</span>{\\n                    visited[nxtNode]=<span class=\\"hljs-literal\\">true</span>\\n                    succSave[nxtNode]=nxtSucc\\n                    arr.push([nxtNode,nxtSucc])\\n                }\\n            }\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"path-with-maximum-probability","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u7531 <code>n</code> \u4e2a\u8282\u70b9\uff08\u4e0b\u6807\u4ece 0 \u5f00\u59cb\uff09\u7ec4\u6210\u7684\u65e0\u5411\u52a0\u6743\u56fe\uff0c\u8be5\u56fe\u7531\u4e00\u4e2a\u63cf\u8ff0\u8fb9\u7684\u5217\u8868\u7ec4\u6210\uff0c\u5176\u4e2d <code>edges[i] = [a, b]</code> \u8868\u793a\u8fde\u63a5\u8282\u70b9 a \u548c b \u7684\u4e00\u6761\u65e0\u5411\u8fb9\uff0c\u4e14\u8be5\u8fb9\u904d\u5386\u6210\u529f\u7684\u6982\u7387\u4e3a <code>succProb[i]</code> \u3002</p>\\n\\n<p>\u6307\u5b9a\u4e24\u4e2a\u8282\u70b9\u5206\u522b\u4f5c\u4e3a\u8d77\u70b9 <code>start</code> \u548c\u7ec8\u70b9 <code>end</code> \uff0c\u8bf7\u4f60\u627e\u51fa\u4ece\u8d77\u70b9\u5230\u7ec8\u70b9\u6210\u529f\u6982\u7387\u6700\u5927\u7684\u8def\u5f84\uff0c\u5e76\u8fd4\u56de\u5176\u6210\u529f\u6982\u7387\u3002</p>\\n\\n<p>\u5982\u679c\u4e0d\u5b58\u5728\u4ece <code>start</code> \u5230 <code>end</code> \u7684\u8def\u5f84\uff0c\u8bf7 <strong>\u8fd4\u56de 0</strong> \u3002\u53ea\u8981\u7b54\u6848\u4e0e\u6807\u51c6\u7b54\u6848\u7684\u8bef\u5dee\u4e0d\u8d85\u8fc7 <strong>1e-5 </strong>\uff0c\u5c31\u4f1a\u88ab\u89c6\u4f5c\u6b63\u786e\u7b54\u6848\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/07/12/1558_ex1.png\\" style=\\"height: 186px; width: 187px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, edges = [[0,1],[1,2],[0,2]], succProb = [0.5,0.5,0.2], start = 0, end = 2\\n<strong>\u8f93\u51fa\uff1a</strong>0.25000\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u8d77\u70b9\u5230\u7ec8\u70b9\u6709\u4e24\u6761\u8def\u5f84\uff0c\u5176\u4e2d\u4e00\u6761\u7684\u6210\u529f\u6982\u7387\u4e3a 0.2 \uff0c\u800c\u53e6\u4e00\u6761\u4e3a 0.5 * 0.5 = 0.25\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/07/12/1558_ex2.png\\" style=\\"height: 186px; width: 189px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, edges = [[0,1],[1,2],[0,2]], succProb = [0.5,0.5,0.3], start = 0, end = 2\\n<strong>\u8f93\u51fa\uff1a</strong>0.30000\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/07/12/1558_ex3.png\\" style=\\"height: 191px; width: 215px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 3, edges = [[0,1]], succProb = [0.5], start = 0, end = 2\\n<strong>\u8f93\u51fa\uff1a</strong>0.00000\\n<strong>\u89e3\u91ca\uff1a</strong>\u8282\u70b9 0 \u548c \u8282\u70b9 2 \u4e4b\u95f4\u4e0d\u5b58\u5728\u8def\u5f84\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 &lt;= n &lt;= 10^4</code></li>\\n\\t<li><code>0 &lt;= start, end &lt; n</code></li>\\n\\t<li><code>start != end</code></li>\\n\\t<li><code>0 &lt;= a, b &lt; n</code></li>\\n\\t<li><code>a != b</code></li>\\n\\t<li><code>0 &lt;= succProb.length == edges.length &lt;= 2*10^4</code></li>\\n\\t<li><code>0 &lt;= succProb[i] &lt;= 1</code></li>\\n\\t<li>\u6bcf\u4e24\u4e2a\u8282\u70b9\u4e4b\u95f4\u6700\u591a\u6709\u4e00\u6761\u8fb9</li>\\n</ul>\\n","title":"1514. \u6982\u7387\u6700\u5927\u7684\u8def\u5f84","relatedTags":["\u56fe"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1514"}')}}]);